pageStyles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    .field-input {
      width: 100%;
      padding: 0.75rem 1rem;
      border: 1px solid #E8E8E8;
      background: #faf8f5;
      font-size: 0.875rem;
      color: #0F2640;
      outline: none;
      transition: border-color 0.2s;
      font-family: inherit;
    }
    .field-input:focus { border-color: #D4AF37; }
    .field-input::placeholder { color: #9CA3AF; }
    select.field-input {
      -webkit-appearance: none;
      -moz-appearance: none;
      appearance: none;
      background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='16' height='16' viewBox='0 0 24 24' fill='none' stroke='%230f2640' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'><polyline points='6 9 12 15 18 9'></polyline></svg>");
      background-repeat: no-repeat;
      background-position: right 12px center;
      background-size: 16px;
      padding-right: 2.5rem;
    }
    label.field-label {
      display: block;
      font-size: 10px;
      letter-spacing: 0.1em;
      text-transform: uppercase;
      font-weight: 700;
      color: #0F2640;
      margin-bottom: 0.375rem;
    }
    @keyframes fadeInUp {
      from { opacity: 0; transform: translateY(16px); }
      to { opacity: 1; transform: translateY(0); }
    }
    .anim { animation: fadeInUp 0.5s ease forwards; }
